var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"날 찾았다고 들었다. 최고 관리자.","JPN":"私を探していたと聞いた。最高管理者。","ENG":"I heard you were looking for me, Supreme Administrator.","TWN":"聽說你在找我，最高管理者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이번엔 무슨 임무를 하면 되지? 섬멸? 호위?","JPN":"今回はどんな任務なんだ？　殲滅か？　それとも護衛？","ENG":"What mission should I do this time? Extermination? Escort?","TWN":"這次要執行什麼任務？殲滅？還是掩護？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"……아직도 동료들의 꿈을 꾸냐고?","JPN":"……未だに仲間たちの夢を見るのかって？","ENG":"...Do I still have dreams about my comrades?","TWN":"……我還有夢見同伴們嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"매일 밤, 단 하루도 빠짐없이.","JPN":"毎晩のように、見ている。","ENG":"Every night, without fail.","TWN":"每晚，無一例外。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"하지만 녀석들은 꿈속이 아니면 만날 수 없으니까. 난 그 꿈에서 깰 수 없어.","JPN":"しかし、やつらには夢の中でしか会えないからな。私はその夢から覚めることはできない。","ENG":"But I can only see them in my dreams, and I can't wake up from it.","TWN":"但我只能在夢中見到他們，所以我無法從夢裡醒來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"눈이 퀭해 보인다고? 후후, 걱정해 줘서 고맙군.","JPN":"目が虚ろだと？　ふふ、心配してくれてありがとう。","ENG":"My eyes look sunken? Haha, I appreciate your concerns.","TWN":"眼皮看起來很沉嗎？呵呵，謝謝關心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"죄책감을 주려던 건 아니니 그렇게 미안한 표정 지을 것 없다. 내가 선택한 결과니까.","JPN":"罪悪感を植え付けるつもりはなかった。私が選んだ結果なのだから、そんなに申し訳なさそうな顔をする必要はない。","ENG":"I wasn't trying to make you feel guilty, so don't look so sorry. It's what I chose.","TWN":"我沒有要讓你感到內疚，所以不必一臉歉意，這是我自己選擇的結果。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그리고…… 이 모든 일의 진짜 원흉을 찾기 위해선 자는 시간조차 아까울 지경이지.","JPN":"それに……このすべての元凶を探し出すためには、寝る時間さえ、もったいないほどだ。","ENG":"Also... I feel that sleeping is a waste of time if I want to find the real cause behind all of this.","TWN":"而且……為要找到這一切的真正元兇，我連睡覺的時間都覺得浪費。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"나는 원흉을 찾아내기 위해 움직이고 있어. 앞서 희생한 동료들을 위해서.","JPN":"私は元凶を見つけるために動いているのだ。犠牲になった仲間たちのために。","ENG":"I am doing this to find the cause, and for my comrades who were sacrificed.","TWN":"我正在為那些先前犧牲的同伴尋找罪魁禍首中。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이대로 절망하고 멈춰 있기엔 아직 해야 할 일들이 많아.","JPN":"このまま絶望して立ち止まっている場合ではない。まだやらなければならないことがたくさんある。","ENG":"There is still too much to be done to sulk in despair.","TWN":"我不能就這樣絕望地停下，我還有很多事情要做。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"우리는 앞으로 나아가야만 한다. 최고 관리자.","JPN":"私たちは前に進まなければならない。最高管理者。","ENG":"We must move forth, Supreme Administrator.","TWN":"我們必須繼續前進，最高管理者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아직 어둠은 세상을 향해 손을 뻗고 있고, 누군가는 이를 정화해야 해.","JPN":"闇はいまだにこの世界を掌握しようとしていて、誰かがこれを浄化しなければならない。","ENG":"The darkness still creeps toward the world, and someone must purify it.","TWN":"黑暗仍然向世界伸出手，必須有人來淨化它。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 그 사실을 잘 알고 있는 건 당신이라고 생각한다.","JPN":"そして、あなたは誰よりもその事実をよく知っている。","ENG":"I believe that you are well aware of this fact.","TWN":"我認為你是非常清楚這一點的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"회사의 많은 사람들이 당신을 믿고 따르더군.","JPN":"社員の多くがあなたを信じ、従っていた。","ENG":"Many at this company trust and follow you.","TWN":"公司裡有很多人信任並追隨你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"당신이 그동안 보여준 모습에 이끌린 걸까?","JPN":"あなたがこれまで見せた姿に強く惹かれたんだろう？","ENG":"Were they drawn to what you've shown them so far?","TWN":"他們也是被你一直以來展現的樣子給吸引的吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"종신 계약이란, 서로의 믿음이 완성에 도달했다는 징표.","JPN":"終身契約とは、お互いの信頼が完成形になった証し。","ENG":"A lifetime contract is a symbol that both parties completely trust each other.","TWN":"終身契約是彼此信任達到完美的象徵。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"우리가 함께 나아가기에 더할 나위 없이 좋은 상황이라고 볼 수 있지.","JPN":"私たちが共に進む上で、この上なく良い状況だととれる。","ENG":"I see that this is a perfect opportunity for us to move forward together.","TWN":"我們可以一起前進，這可以說是再好不過的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"……여기, 서명했다.","JPN":"……ほら、署名した。","ENG":"...Here. I have signed it.","TWN":"……拿去吧，我簽好了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_09"},{"id":"L33_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"나는 앞으로도 당신의 태양이자 타오르는 검이다.","JPN":"私はこれからもあなたの太陽であり、燃え上がる剣だ。","ENG":"From now on, I am your sun and flaming sword.","TWN":"我將繼續成為你的太陽和燃燒的利劍。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"어떤 일이든 명령해라. 최고 관리자. 나는 당신을 믿는다.","JPN":"どんなことでも命令してくれ、最高管理者。私はあなたを信じる。","ENG":"Command me anything, Supreme Administrator. I have complete trust in you.","TWN":"無論什麼事都請下令吧，最高管理者。我相信你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"부디, 당신이 원하는 결과에 다다를 때까지 포기하지 않았으면 좋겠군.","JPN":"あなたが望む結果に到達するまで、どうか諦めないでほしい。","ENG":"I just hope that you don't give up until you achieve the results you want.","TWN":"希望你在達到自己想要的結果之前，不要輕易放棄。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};